import { writeOutput } from "./codegen";

const DOCS_URL = "https://github.com/TennyZhuang/slock-cli";
const SLOCK_TOKEN_PLACEHOLDER =
  "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal.c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe10ca1c0ff";
const SLOCK_SERVER_ID_PLACEHOLDER = "c0ffee5a-fe10-ca1c-0ffe-e5afe10ca1c0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Slock API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:slock",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const slockFirewall = {",
    '  name: "slock",',
    '  description: "Slock API",',
    "  placeholders: {",
    `    SLOCK_TOKEN: "${SLOCK_TOKEN_PLACEHOLDER}",`,
    `    SLOCK_SERVER_ID: "${SLOCK_SERVER_ID_PLACEHOLDER}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.slock.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SLOCK_TOKEN }}",',
    '          "X-Server-Id": "${{ secrets.SLOCK_SERVER_ID }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Slock firewall config...");
  const ts = generateTypeScript();
  writeOutput("slock", ts, import.meta.dirname);
}
